import React, { useEffect, useRef, useState } from 'react';
import ReactAudioPlayer from 'react-audio-player';
import { PlayIcon } from '@heroicons/react/24/solid';

const AudioPlayer = ({ slug }) => {
  const [audioExists, setAudioExists] = useState(false);
  const [showAudioPlayer, setShowAudioPlayer] = useState(false);
  const [audioSrc, setAudioSrc] = useState('');
  const [debugInfo, setDebugInfo] = useState('');
  const audioRef = useRef(null);

  useEffect(() => {
    if (typeof window !== 'undefined') {
      const src = `${window.location.origin}/audio/${slug}.mp3`;
      setAudioSrc(src);
      setDebugInfo((prev) => `${prev}\nChecking audio source: ${src}`);

      // Check if the audio file exists
      const audio = new Audio(src);
      audio.oncanplaythrough = () => {
        setDebugInfo((prev) => `${prev}\nAudio file exists and can play through`);
        setAudioExists(true);
      };
      audio.onerror = () => {
        setDebugInfo((prev) => `${prev}\nAudio file does not exist or cannot play through`);
        setAudioExists(false);
      };
    }
  }, [slug]);

  const handlePlayButtonClick = () => {
    setDebugInfo((prev) => `${prev}\nPlay button clicked`);
    setShowAudioPlayer(true);
  };

  return (
    <>
      <pre>{debugInfo}</pre> 

      {audioExists && !showAudioPlayer && (
        
        <div className="text-to-speech">
          <button onClick={handlePlayButtonClick}>
            <PlayIcon className="h-6 w-6 text-gray-700 mr-2" />
            Play
          </button>
        </div>
      )}
      {showAudioPlayer && (
        <ReactAudioPlayer src={audioSrc} autoPlay controls ref={audioRef} className="audio-player" />
      )}
    </>
  );
};

export default AudioPlayer;
